 1→import { type ReactNode } from 'react';
 2→import { Navigate, useLocation } from 'react-router-dom';
 3→import { useAuth } from '../../hooks/useAuth';
 4→import { Spinner } from '../ui/Spinner';
 5→
 6→interface ProtectedRouteProps {
 7→  children: ReactNode;
 8→}
 9→
10→export function ProtectedRoute({ children }: ProtectedRouteProps) {
11→  const { isAuthenticated, loading } = useAuth();
12→  const location = useLocation();
13→
14→  if (loading) {
15→    return (
16→      <div className="flex min-h-screen items-center justify-center">
17→        <Spinner size="lg" />
18→      </div>
19→    );
20→  }
21→
22→  if (!isAuthenticated) {
23→    return <Navigate to="/login" state={{ from: location }} replace />;
24→  }
25→
26→  return <>{children}</>;
27→}
