 1→import { type ReactNode } from 'react';
 2→import { Navigate } from 'react-router-dom';
 3→import { useAuth } from '../../hooks/useAuth';
 4→import { Spinner } from '../ui/Spinner';
 5→
 6→interface RoleRouteProps {
 7→  children: ReactNode;
 8→  allowedRole: 'merchant' | 'customer';
 9→}
10→
11→export function RoleRoute({ children, allowedRole }: RoleRouteProps) {
12→  const { profile, loading } = useAuth();
13→
14→  if (loading || !profile) {
15→    return (
16→      <div className="flex min-h-screen items-center justify-center">
17→        <Spinner size="lg" />
18→      </div>
19→    );
20→  }
21→
22→  if (profile.role !== allowedRole) {
23→    const redirect =
24→      profile.role === 'merchant'
25→        ? '/merchant/dashboard'
26→        : '/customer/dashboard';
27→    return <Navigate to={redirect} replace />;
28→  }
29→
30→  return <>{children}</>;
31→}
