  1→import { supabaseAdmin } from '../_shared/supabase-admin.ts';
  2→import { getAuthUser } from '../_shared/auth.ts';
  3→import {
  4→  successResponse,
  5→  errorResponse,
  6→  corsResponse,
  7→} from '../_shared/responses.ts';
  8→import { getCustomerIdsForAudience, getPlayerIdsForAudience } from '../_shared/audience.ts';
  9→import { sendPushNotification } from '../_shared/onesignal.ts';
 10→
 11→/**
 12→ * Launch a campaign:
 13→ * 1. Generate unique QR codes per client
 14→ * 2. Send push notifications
 15→ * 3. Update campaign status
 16→ */
 17→Deno.serve(async (req) => {
 18→  if (req.method === 'OPTIONS') {
 19→    return corsResponse();
 20→  }
 21→
 22→  try {
 23→    // 1. Auth
 24→    const user = await getAuthUser(req);
 25→    if (!user) {
 26→      return errorResponse('NOT_AUTHENTICATED', 'Authentification requise', 401);
 27→    }
 28→
 29→    // 2. Get merchant
 30→    const { data: merchant, error: merchantError } = await supabaseAdmin
 31→      .from('merchants')
 32→      .select('id, business_name, subscription_status')
 33→      .eq('profile_id', user.id)
 34→      .single();
 35→
 36→    if (merchantError || !merchant) {
 37→      return errorResponse('NOT_MERCHANT', 'Profil marchand introuvable', 403);
 38→    }
 39→
 40→    // 3. Check subscription
 41→    if (merchant.subscription_status === 'cancelled' || merchant.subscription_status === 'past_due') {
 42→      return errorResponse('SUBSCRIPTION_BLOCKED', 'Abonnement inactif. Renouvelez pour lancer des campagnes.', 403);
 43→    }
 44→
 45→    // 4. Get campaign
 46→    const { campaign_id } = await req.json();
 47→    if (!campaign_id) {
 48→      return errorResponse('INVALID_PAYLOAD', 'campaign_id requis');
 49→    }
 50→
 51→    const { data: campaign, error: campaignError } = await supabaseAdmin
 52→      .from('campaigns')
 53→      .select('*')
 54→      .eq('id', campaign_id)
 55→      .eq('merchant_id', merchant.id)
 56→      .single();
 57→
 58→    if (campaignError || !campaign) {
 59→      return errorResponse('CAMPAIGN_NOT_FOUND', 'Campagne introuvable');
 60→    }
 61→
 62→    if (!campaign) {
 63→      return errorResponse('NOT_OWNER', 'Cette campagne ne vous appartient pas', 403);
 64→    }
 65→
 66→    if (campaign.status !== 'draft' && campaign.status !== 'scheduled') {
 67→      return errorResponse('INVALID_STATUS', 'La campagne doit etre en brouillon ou planifiee pour etre lancee');
 68→    }
 69→
 70→    // 5. Get targeted customers
 71→    const customerIds = await getCustomerIdsForAudience(merchant.id, campaign.target_audience);
 72→
 73→    if (customerIds.length === 0) {
 74→      return errorResponse('NO_CLIENTS', 'Aucun client dans l\'audience ciblee');
 75→    }
 76→
 77→    // 6. Generate QR codes in batch
 78→    const expiresAt = campaign.completed_at
 79→      || new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
 80→
 81→    const qrInserts = customerIds.map((customerId) => ({
 82→      merchant_id: merchant.id,
 83→      qr_type: 'campaign' as const,
 84→      campaign_id: campaign.id,
 85→      customer_id: customerId,
 86→      expires_at: expiresAt,
 87→      max_uses: 1,
 88→      uses_count: 0,
 89→      is_active: true,
 90→    }));
 91→
 92→    const { data: insertedQRs, error: qrError } = await supabaseAdmin
 93→      .from('qr_codes')
 94→      .insert(qrInserts)
 95→      .select('id, token, customer_id');
 96→
 97→    if (qrError) {
 98→      console.error('QR insert error:', qrError);
 99→      return errorResponse('INTERNAL_ERROR', 'Erreur lors de la generation des QR codes', 500);
100→    }
101→
102→    const qrCodesGenerated = insertedQRs?.length ?? 0;
103→
104→    // 7. Send push notifications (Option A: generic URL /campaign/{campaignId})
105→    const appUrl = Deno.env.get('SITE_URL') || '';
106→    const campaignUrl = `${appUrl}/campaign/${campaign.id}`;
107→
108→    const playerIds = await getPlayerIdsForAudience(merchant.id, campaign.target_audience);
109→
110→    let pushSent = 0;
111→    let pushFailed = 0;
112→
113→    if (playerIds.length > 0) {
114→      try {
115→        const result = await sendPushNotification({
116→          playerIds,
117→          title: campaign.title,
118→          message: campaign.message,
119→          data: {
120→            campaign_id: campaign.id,
121→            merchant_id: merchant.id,
122→            merchant_name: merchant.business_name,
123→          },
124→          url: campaignUrl,
125→        });
126→        pushSent = result.recipients;
127→        pushFailed = playerIds.length - result.recipients;
128→      } catch (pushErr) {
129→        console.error('Push notification error:', pushErr);
130→        pushFailed = playerIds.length;
131→      }
132→    }
133→
134→    // 8. Update campaign status
135→    await supabaseAdmin
136→      .from('campaigns')
137→      .update({
138→        status: 'active',
139→        started_at: new Date().toISOString(),
140→        total_sent: customerIds.length,
141→      })
142→      .eq('id', campaign.id);
143→
144→    // 9. Return summary
145→    return successResponse({
146→      campaign_id: campaign.id,
147→      clients_targeted: customerIds.length,
148→      qr_codes_generated: qrCodesGenerated,
149→      push_sent: pushSent,
150→      push_failed: pushFailed,
151→    });
152→  } catch (err) {
153→    console.error('launch-campaign error:', err);
154→    return errorResponse('INTERNAL_ERROR', 'Erreur serveur inattendue', 500);
155→  }
156→});
