10→/**
11→ * Generic push notification sender.
12→ * Accepts a list of player_ids and sends a notification to them.
13→ * Restricted to authenticated users.
14→ */
15→Deno.serve(async (req) => {
16→  if (req.method === 'OPTIONS') {
17→    return corsResponse();
18→  }
19→
20→  try {
21→    const user = await getAuthUser(req);
22→    if (!user) {
23→      return errorResponse('NOT_AUTHENTICATED', 'Authentification requise', 401);
24→    }
25→
26→    const { player_ids, title, message, data, url } = await req.json();
27→
28→    if (!player_ids || !Array.isArray(player_ids) || player_ids.length === 0) {
29→      return errorResponse('INVALID_PAYLOAD', 'player_ids requis (tableau non vide)');
30→    }
31→
32→    if (!title || !message) {
33→      return errorResponse('INVALID_PAYLOAD', 'title et message requis');
34→    }
35→
36→    const result = await sendPushNotification({
37→      playerIds: player_ids,
38→      title,
39→      message,
40→      data,
41→      url,
42→    });
43→
44→    return successResponse(result);
45→  } catch (err) {
46→    console.error('send-push-notification error:', err);
47→    return errorResponse('INTERNAL_ERROR', 'Erreur serveur inattendue', 500);
48→  }
49→});
