  1→import { supabaseAdmin } from '../_shared/supabase-admin.ts';
  2→import { getAuthUser } from '../_shared/auth.ts';
  3→import {
  4→  successResponse,
  5→  errorResponse,
  6→  corsResponse,
  7→} from '../_shared/responses.ts';
  8→import { sendPushNotification } from '../_shared/onesignal.ts';
  9→import { getPlayerIdsForAudience } from '../_shared/audience.ts';
 10→
 11→/**
 12→ * Merchant-specific push notification sender.
 13→ * Verifies the caller is a merchant, then sends targeted push
 14→ * based on audience segment.
 15→ */
 16→Deno.serve(async (req) => {
 17→  if (req.method === 'OPTIONS') {
 18→    return corsResponse();
 19→  }
 20→
 21→  try {
 22→    // 1. Auth
 23→    const user = await getAuthUser(req);
 24→    if (!user) {
 25→      return errorResponse('NOT_AUTHENTICATED', 'Authentification requise', 401);
 26→    }
 27→
 28→    // 2. Verify caller is a merchant
 29→    const { data: merchant, error: merchantError } = await supabaseAdmin
 30→      .from('merchants')
 31→      .select('id, business_name')
 32→      .eq('profile_id', user.id)
 33→      .single();
 34→
 35→    if (merchantError || !merchant) {
 36→      return errorResponse('NOT_MERCHANT', 'Seuls les marchands peuvent envoyer des notifications', 403);
 37→    }
 38→
 39→    // 3. Parse body
 40→    const { title, message, target_audience, campaign_id, offer_token } = await req.json();
 41→
 42→    if (!title || !message) {
 43→      return errorResponse('INVALID_PAYLOAD', 'title et message requis');
 44→    }
 45→
 46→    const audience = target_audience || 'all';
 47→    const validAudiences = ['all', 'active', 'inactive', 'new', 'vip'];
 48→    if (!validAudiences.includes(audience)) {
 49→      return errorResponse('INVALID_AUDIENCE', `Audience invalide. Valeurs: ${validAudiences.join(', ')}`);
 50→    }
 51→
 52→    // 4. Get player IDs for audience
 53→    const playerIds = await getPlayerIdsForAudience(merchant.id, audience);
 54→
 55→    if (playerIds.length === 0) {
 56→      return successResponse({
 57→        notification_id: '',
 58→        recipients: 0,
 59→      });
 60→    }
 61→
 62→    // 5. Build notification data
 63→    const data: Record<string, unknown> = {
 64→      merchant_id: merchant.id,
 65→      merchant_name: merchant.business_name,
 66→    };
 67→
 68→    if (campaign_id) {
 69→      data.campaign_id = campaign_id;
 70→    }
 71→
 72→    let url: string | undefined;
 73→    if (offer_token) {
 74→      url = `${Deno.env.get('SITE_URL') || ''}/offer/${offer_token}`;
 75→    }
 76→
 77→    // 6. Send push
 78→    const result = await sendPushNotification({
 79→      playerIds,
 80→      title,
 81→      message,
 82→      data,
 83→      url,
 84→    });
 85→
 86→    // 7. If campaign_id, update campaign stats
 87→    if (campaign_id) {
 88→      await supabaseAdmin
 89→        .from('campaigns')
 90→        .update({
 91→          total_sent: result.recipients,
 92→          status: 'sent',
 93→          started_at: new Date().toISOString(),
 94→        })
 95→        .eq('id', campaign_id)
 96→        .eq('merchant_id', merchant.id);
 97→    }
 98→
 99→    return successResponse(result);
100→  } catch (err) {
101→    console.error('send-merchant-push error:', err);
102→    return errorResponse('INTERNAL_ERROR', 'Erreur serveur inattendue', 500);
103→  }
104→});
