  1→import { corsHeaders } from '../_shared/cors.ts';
  2→import { supabaseAdmin } from '../_shared/supabase-admin.ts';
  3→import { getAuthUser } from '../_shared/auth.ts';
  4→import {
  5→  successResponse,
  6→  errorResponse,
  7→  corsResponse,
  8→} from '../_shared/responses.ts';
  9→import { stripe } from '../_shared/stripe.ts';
 10→
 11→const priceMap: Record<string, string> = {
 12→  starter: Deno.env.get('STRIPE_PRICE_STARTER') || '',
 13→  pro: Deno.env.get('STRIPE_PRICE_PRO') || '',
 14→  business: Deno.env.get('STRIPE_PRICE_BUSINESS') || '',
 15→};
 16→
 17→Deno.serve(async (req) => {
 18→  if (req.method === 'OPTIONS') {
 19→    return corsResponse();
 20→  }
 21→
 22→  try {
 23→    // 1. Auth
 24→    const user = await getAuthUser(req);
 25→    if (!user) {
 26→      return errorResponse('NOT_AUTHENTICATED', 'Authentification requise', 401);
 27→    }
 28→
 29→    // 2. Get profile + verify merchant role
 30→    const { data: profile } = await supabaseAdmin
 31→      .from('profiles')
 32→      .select('id, email, role')
 33→      .eq('id', user.id)
 34→      .single();
 35→
 36→    if (!profile || profile.role !== 'merchant') {
 37→      return errorResponse('NOT_MERCHANT', 'Seuls les marchands peuvent souscrire');
 38→    }
 39→
 40→    // 3. Get merchant
 41→    const { data: merchant } = await supabaseAdmin
 42→      .from('merchants')
 43→      .select('id, stripe_customer_id, subscription_status, subscription_plan, had_trial')
 44→      .eq('profile_id', profile.id)
 45→      .single();
 46→
 47→    if (!merchant) {
 48→      return errorResponse('MERCHANT_NOT_FOUND', 'Marchand introuvable');
 49→    }
 50→
 51→    // 4. Parse body
 52→    const { plan, success_url, cancel_url } = await req.json();
 53→
 54→    if (!plan || !priceMap[plan]) {
 55→      return errorResponse('INVALID_PLAN', 'Plan non reconnu. Choisissez starter, pro ou business.');
 56→    }
 57→
 58→    // 5. Check if already active on same plan
 59→    if (
 60→      merchant.subscription_status === 'active' &&
 61→      merchant.subscription_plan === plan
 62→    ) {
 63→      return errorResponse(
 64→        'ALREADY_ACTIVE',
 65→        'Vous etes deja abonne a ce plan. Utilisez le portail pour modifier votre abonnement.'
 66→      );
 67→    }
 68→
 69→    // 6. If already has active subscription, redirect to portal for upgrade/downgrade
 70→    if (
 71→      merchant.stripe_customer_id &&
 72→      (merchant.subscription_status === 'active' || merchant.subscription_status === 'trial')
 73→    ) {
 74→      return errorResponse(
 75→        'USE_PORTAL',
 76→        'Utilisez le portail client pour changer de plan.'
 77→      );
 78→    }
 79→
 80→    const appUrl = Deno.env.get('APP_URL') || 'http://localhost:5173';
 81→    const successUrl = success_url || `${appUrl}/merchant/billing/success?session_id={CHECKOUT_SESSION_ID}`;
 82→    const cancelUrl = cancel_url || `${appUrl}/merchant/billing`;
 83→
 84→    // 7. Build checkout session params
 85→    const sessionParams: Record<string, unknown> = {
 86→      mode: 'subscription',
 87→      payment_method_types: ['card'],
 88→      line_items: [
 89→        {
 90→          price: priceMap[plan],
 91→          quantity: 1,
 92→        },
 93→      ],
 94→      success_url: successUrl,
 95→      cancel_url: cancelUrl,
 96→      metadata: {
 97→        merchant_id: merchant.id,
 98→        profile_id: profile.id,
 99→        plan: plan,
100→      },
101→      allow_promotion_codes: true,
102→      billing_address_collection: 'auto',
103→      tax_id_collection: { enabled: true },
104→    };
105→
106→    // Reuse existing Stripe customer if exists
107→    if (merchant.stripe_customer_id) {
108→      sessionParams.customer = merchant.stripe_customer_id;
109→    } else {
110→      sessionParams.customer_email = profile.email;
111→    }
112→
113→    // Add trial if merchant hasn't had one before
114→    if (!merchant.had_trial && merchant.subscription_status !== 'active') {
115→      sessionParams.subscription_data = {
116→        trial_period_days: 14,
117→        metadata: {
118→          merchant_id: merchant.id,
119→          plan: plan,
120→        },
121→      };
122→    } else {
123→      sessionParams.subscription_data = {
124→        metadata: {
125→          merchant_id: merchant.id,
126→          plan: plan,
127→        },
128→      };
129→    }
130→
131→    // 8. Create Stripe Checkout Session
132→    // deno-lint-ignore no-explicit-any
133→    const session = await (stripe.checkout.sessions as any).create(sessionParams);
134→
135→    return successResponse({
136→      checkout_url: session.url,
137→      session_id: session.id,
138→    });
139→  } catch (err) {
140→    console.error('create-checkout-session error:', err);
141→    if (err instanceof Error && err.message.includes('Stripe')) {
142→      return errorResponse('STRIPE_ERROR', err.message, 500);
143→    }
144→    return errorResponse('INTERNAL_ERROR', 'Erreur serveur inattendue', 500);
145→  }
146→});
