  1→import { supabaseAdmin } from '../_shared/supabase-admin.ts';
  2→import {
  3→  stripe,
  4→  mapStripeStatus,
  5→  getPlanFromPriceId,
  6→  getMerchantByStripeCustomer,
  7→  notifyMerchant,
  8→  logBillingEvent,
  9→} from '../_shared/stripe.ts';
 10→import type Stripe from 'https://esm.sh/stripe@14';
 11→
 12→// -------------------------------------------------------
 13→// STRIPE WEBHOOK HANDLER
 14→// No JWT auth — verifies Stripe signature only
 15→// -------------------------------------------------------
 16→
 17→Deno.serve(async (req) => {
 18→  if (req.method === 'OPTIONS') {
 19→    return new Response('ok', { status: 200 });
 20→  }
 21→
 22→  // Only accept POST
 23→  if (req.method !== 'POST') {
 24→    return new Response('Method not allowed', { status: 405 });
 25→  }
 26→
 27→  try {
 28→    const body = await req.text();
 29→    const signature = req.headers.get('stripe-signature');
 30→
 31→    if (!signature) {
 32→      return new Response('Missing stripe-signature header', { status: 400 });
 33→    }
 34→
 35→    // CRITICAL: Verify Stripe webhook signature
 36→    let event: Stripe.Event;
 37→    try {
 38→      event = await stripe.webhooks.constructEventAsync(
 39→        body,
 40→        signature,
 41→        Deno.env.get('STRIPE_WEBHOOK_SECRET')!
 42→      );
 43→    } catch (err) {
 44→      console.error('Webhook signature verification failed:', err);
 45→      return new Response(
 46→        `Webhook signature verification failed: ${err instanceof Error ? err.message : 'unknown'}`,
 47→        { status: 400 }
 48→      );
 49→    }
 50→
 51→    // IDEMPOTENCE: Check if event already processed
 52→    const { data: existing } = await supabaseAdmin
 53→      .from('billing_events')
 54→      .select('id')
 55→      .eq('stripe_event_id', event.id)
 56→      .maybeSingle();
 57→
 58→    if (existing) {
 59→      return new Response('Event already processed', { status: 200 });
 60→    }
 61→
 62→    // ─── HANDLE EVENTS ───────────────────────────────────────
 63→
 64→    switch (event.type) {
 65→      // ─── CHECKOUT COMPLETED ──────────────────────────────────
 66→      case 'checkout.session.completed': {
 67→        const session = event.data.object as Stripe.Checkout.Session;
 68→        const merchantId = session.metadata?.merchant_id;
 69→        const plan = session.metadata?.plan;
 70→        const customerId = session.customer as string;
 71→        const subscriptionId = session.subscription as string;
 72→
 73→        if (merchantId && plan) {
 74→          await supabaseAdmin
 75→            .from('merchants')
 76→            .update({
 77→              stripe_customer_id: customerId,
 78→              stripe_subscription_id: subscriptionId,
 79→              subscription_plan: plan,
 80→              // Status will be set by subscription.created/updated event
 81→            })
 82→            .eq('id', merchantId);
 83→        }
 84→
 85→        await logBillingEvent(
 86→          'checkout_completed',
 87→          merchantId || null,
 88→          { plan, customerId, subscriptionId },
 89→          event.id
 90→        );
 91→        break;
 92→      }
 93→
 94→      // ─── SUBSCRIPTION CREATED ────────────────────────────────
 95→      case 'customer.subscription.created': {
 96→        const subscription = event.data.object as Stripe.Subscription;
 97→        const customerId = subscription.customer as string;
 98→        const merchantId = subscription.metadata?.merchant_id || null;
 99→
100→        const status = mapStripeStatus(subscription.status);
101→        const plan = getPlanFromPriceId(
102→          subscription.items.data[0]?.price.id || ''
103→        );
104→
105→        const updateData: Record<string, unknown> = {
106→          subscription_status: status,
107→          subscription_plan: plan,
108→          stripe_subscription_id: subscription.id,
109→        };
110→
111→        // Set trial_ends_at if trialing
112→        if (subscription.status === 'trialing' && subscription.trial_end) {
113→          updateData.trial_ends_at = new Date(
114→            subscription.trial_end * 1000
115→          ).toISOString();
116→        }
117→
118→        // Update by stripe_customer_id or merchant_id
119→        if (merchantId) {
120→          await supabaseAdmin
121→            .from('merchants')
122→            .update(updateData)
123→            .eq('id', merchantId);
124→        } else {
125→          await supabaseAdmin
126→            .from('merchants')
127→            .update(updateData)
128→            .eq('stripe_customer_id', customerId);
129→        }
130→
131→        await logBillingEvent(
132→          'subscription_created',
133→          merchantId,
134→          { status, plan, customerId },
135→          event.id
136→        );
137→        break;
138→      }
139→
140→      // ─── SUBSCRIPTION UPDATED (plan change, trial end, etc.) ─
141→      case 'customer.subscription.updated': {
142→        const subscription = event.data.object as Stripe.Subscription;
143→        const customerId = subscription.customer as string;
144→        // deno-lint-ignore no-explicit-any
145→        const previousAttributes = (event.data as any)
146→          .previous_attributes as Record<string, unknown> | undefined;
147→
148→        const status = mapStripeStatus(subscription.status);
149→        const plan = getPlanFromPriceId(
150→          subscription.items.data[0]?.price.id || ''
151→        );
152→
153→        const updateData: Record<string, unknown> = {
154→          subscription_status: status,
155→          subscription_plan: plan,
156→        };
157→
158→        // If trial just ended
159→        if (
160→          previousAttributes?.status === 'trialing' &&
161→          subscription.status !== 'trialing'
162→        ) {
163→          updateData.trial_ends_at = null;
164→        }
165→
166→        // Update trial_ends_at if still trialing
167→        if (subscription.status === 'trialing' && subscription.trial_end) {
168→          updateData.trial_ends_at = new Date(
169→            subscription.trial_end * 1000
170→          ).toISOString();
171→        }
172→
173→        await supabaseAdmin
174→          .from('merchants')
175→          .update(updateData)
176→          .eq('stripe_customer_id', customerId);
177→
178→        // Log plan change if applicable
179→        // deno-lint-ignore no-explicit-any
180→        const prevItems = (previousAttributes?.items as any)?.data;
181→        const previousPriceId = prevItems?.[0]?.price?.id;
182→        if (
183→          previousPriceId &&
184→          previousPriceId !== subscription.items.data[0]?.price.id
185→        ) {
186→          const merchant = await getMerchantByStripeCustomer(customerId);
187→          await logBillingEvent(
188→            'plan_changed',
189→            merchant?.id || null,
190→            {
191→              from: getPlanFromPriceId(previousPriceId),
192→              to: plan,
193→              customer: customerId,
194→            },
195→            event.id
196→          );
197→        } else {
198→          await logBillingEvent(
199→            'subscription_updated',
200→            null,
201→            { status, plan, customer: customerId },
202→            event.id
203→          );
204→        }
205→        break;
206→      }
207→
208→      // ─── SUBSCRIPTION DELETED (cancellation) ─────────────────
209→      case 'customer.subscription.deleted': {
210→        const subscription = event.data.object as Stripe.Subscription;
211→        const customerId = subscription.customer as string;
212→
213→        await supabaseAdmin
214→          .from('merchants')
215→          .update({
216→            subscription_status: 'cancelled',
217→          })
218→          .eq('stripe_customer_id', customerId);
219→
220→        const merchant = await getMerchantByStripeCustomer(customerId);
221→        if (merchant) {
222→          await notifyMerchant(merchant.id, {
223→            title: 'Abonnement annule',
224→            message:
225→              'Votre abonnement AstroLab a ete annule. Vos donnees seront conservees 30 jours.',
226→          });
227→
228→          await logBillingEvent(
229→            'subscription_cancelled',
230→            merchant.id,
231→            { customer: customerId },
232→            event.id
233→          );
234→        }
235→        break;
236→      }
237→
238→      // ─── PAYMENT SUCCEEDED ───────────────────────────────────
239→      case 'invoice.payment_succeeded': {
240→        const invoice = event.data.object as Stripe.Invoice;
241→        const customerId = invoice.customer as string;
242→
243→        // Only handle renewals (not first payment)
244→        if (invoice.billing_reason === 'subscription_cycle') {
245→          await supabaseAdmin
246→            .from('merchants')
247→            .update({ subscription_status: 'active' })
248→            .eq('stripe_customer_id', customerId);
249→        }
250→
251→        const merchant = await getMerchantByStripeCustomer(customerId);
252→        await logBillingEvent(
253→          'payment_succeeded',
254→          merchant?.id || null,
255→          {
256→            amount: invoice.amount_paid,
257→            currency: invoice.currency,
258→            customer: customerId,
259→            billing_reason: invoice.billing_reason,
260→          },
261→          event.id
262→        );
263→        break;
264→      }
265→
266→      // ─── PAYMENT FAILED ──────────────────────────────────────
267→      case 'invoice.payment_failed': {
268→        const invoice = event.data.object as Stripe.Invoice;
269→        const customerId = invoice.customer as string;
270→
271→        await supabaseAdmin
272→          .from('merchants')
273→          .update({ subscription_status: 'past_due' })
274→          .eq('stripe_customer_id', customerId);
275→
276→        const merchant = await getMerchantByStripeCustomer(customerId);
277→        if (merchant) {
278→          await notifyMerchant(merchant.id, {
279→            title: 'Paiement echoue',
280→            message:
281→              'Votre paiement AstroLab a echoue. Mettez a jour votre carte pour eviter l\'interruption.',
282→          });
283→
284→          await logBillingEvent(
285→            'payment_failed',
286→            merchant.id,
287→            {
288→              amount: invoice.amount_due,
289→              attempt_count: invoice.attempt_count,
290→              customer: customerId,
291→            },
292→            event.id
293→          );
294→        }
295→        break;
296→      }
297→
298→      // ─── TRIAL ENDING SOON (3 days before) ───────────────────
299→      case 'customer.subscription.trial_will_end': {
300→        const subscription = event.data.object as Stripe.Subscription;
301→        const customerId = subscription.customer as string;
302→
303→        const merchant = await getMerchantByStripeCustomer(customerId);
304→        if (merchant) {
305→          await notifyMerchant(merchant.id, {
306→            title: 'Votre essai se termine dans 3 jours',
307→            message:
308→              'Ajoutez une carte bancaire pour continuer a utiliser AstroLab sans interruption.',
309→          });
310→
311→          await logBillingEvent(
312→            'trial_ending_soon',
313→            merchant.id,
314→            {
315→              trial_end: subscription.trial_end,
316→              customer: customerId,
317→            },
318→            event.id
319→          );
320→        }
321→        break;
322→      }
323→
324→      default:
325→        console.log(`Unhandled event type: ${event.type}`);
326→    }
327→
328→    return new Response(JSON.stringify({ received: true }), {
329→      status: 200,
330→      headers: { 'Content-Type': 'application/json' },
331→    });
332→  } catch (err) {
333→    console.error('stripe-webhook-handler error:', err);
334→    return new Response(
335→      JSON.stringify({
336→        error: err instanceof Error ? err.message : 'Unexpected error',
337→      }),
338→      { status: 500, headers: { 'Content-Type': 'application/json' } }
339→    );
340→  }
341→});
