 11→// -------------------------------------------------------
 12→// HMAC-SHA256 signature validation
 13→// -------------------------------------------------------
 14→async function validateSignature(
 15→  body: string,
 16→  signature: string,
 17→  secret: string
 18→): Promise<boolean> {
 19→  const encoder = new TextEncoder();
 20→  const key = await crypto.subtle.importKey(
 21→    'raw',
 22→    encoder.encode(secret),
 23→    { name: 'HMAC', hash: 'SHA-256' },
 24→    false,
 25→    ['sign']
 26→  );
 27→  const sig = await crypto.subtle.sign('HMAC', key, encoder.encode(body));
 28→  const expected = Array.from(new Uint8Array(sig))
 29→    .map((b) => b.toString(16).padStart(2, '0'))
 30→    .join('');
 31→  return signature === expected;
 32→}
