 75→async function handleLaunchCampaign(data: Record<string, unknown>) {
 76→  // Forward to launch-campaign edge function via internal call
 77→  const campaignId = data.campaign_id as string;
 78→  if (!campaignId) throw new Error('campaign_id required');
 79→
 80→  // Direct DB operations to launch the campaign (same logic as launch-campaign)
 81→  const { data: campaign, error: campaignError } = await supabaseAdmin
 82→    .from('campaigns')
 83→    .select('*, merchants!inner(subscription_status, subscription_plan)')
 84→    .eq('id', campaignId)
 85→    .single();
 86→
 87→  if (campaignError || !campaign) throw new Error('Campaign not found');
 88→  if (campaign.status !== 'draft' && campaign.status !== 'scheduled') {
 89→    throw new Error(`Invalid campaign status: ${campaign.status}`);
 90→  }
 91→
 92→  // Update status to active
 93→  const { error: updateError } = await supabaseAdmin
 94→    .from('campaigns')
 95→    .update({
 96→      status: 'active',
 97→      started_at: new Date().toISOString(),
 98→    })
 99→    .eq('id', campaignId);
100→
101→  if (updateError) throw new Error(`Launch failed: ${updateError.message}`);
102→  return { launched: true, campaign_id: campaignId };
103→}
