161→async function handleSendPush(data: Record<string, unknown>) {
162→  const ONESIGNAL_APP_ID = Deno.env.get('ONESIGNAL_APP_ID');
163→  const ONESIGNAL_REST_API_KEY = Deno.env.get('ONESIGNAL_REST_API_KEY');
164→
165→  if (!ONESIGNAL_APP_ID || !ONESIGNAL_REST_API_KEY) {
166→    throw new Error('OneSignal env vars not configured');
167→  }
168→
169→  const body: Record<string, unknown> = {
170→    app_id: ONESIGNAL_APP_ID,
171→    headings: { en: data.title || 'AstroLab' },
172→    contents: { en: data.message },
173→  };
174→
175→  if (data.include_player_ids) {
176→    body.include_player_ids = data.include_player_ids;
177→  } else if (data.include_external_user_ids) {
178→    body.include_external_user_ids = data.include_external_user_ids;
179→  }
180→
181→  if (data.url) body.url = data.url;
182→
183→  const res = await fetch('https://onesignal.com/api/v1/notifications', {
184→    method: 'POST',
185→    headers: {
186→      'Content-Type': 'application/json',
187→      Authorization: `Basic ${ONESIGNAL_REST_API_KEY}`,
188→    },
189→    body: JSON.stringify(body),
190→  });
191→
192→  if (!res.ok) {
193→    const text = await res.text();
194→    throw new Error(`OneSignal error: ${res.status} — ${text}`);
195→  }
196→
197→  const result = await res.json();
198→  return { push_sent: true, onesignal_id: result.id };
199→}
