201→async function handleCompleteCampaign(data: Record<string, unknown>) {
202→  const campaignId = data.campaign_id as string;
203→  if (!campaignId) throw new Error('campaign_id required');
204→
205→  // Update campaign status
206→  const { error: campaignError } = await supabaseAdmin
207→    .from('campaigns')
208→    .update({
209→      status: 'completed',
210→      completed_at: new Date().toISOString(),
211→    })
212→    .eq('id', campaignId)
213→    .eq('status', 'active');
214→
215→  if (campaignError) throw new Error(`Complete failed: ${campaignError.message}`);
216→
217→  // Deactivate QR codes
218→  await supabaseAdmin
219→    .from('qr_codes')
220→    .update({ is_active: false })
221→    .eq('campaign_id', campaignId);
222→
223→  return { completed: true, campaign_id: campaignId };
224→}
