 10→/**
 11→ * check-trial-expiry
 12→ * Called daily by n8n cron to:
 13→ * 1. Find merchants whose trial expires in <= 3 days
 14→ * 2. Send push notifications to remind them
 15→ * 3. Find merchants whose trial has expired
 16→ * 4. Downgrade them to cancelled status
 17→ */
 18→serve(async (req: Request) => {
 19→  if (req.method === 'OPTIONS') {
 20→    return new Response('ok', { headers: corsHeaders });
 21→  }
 22→
 23→  try {
 24→    // Verify webhook secret
 25→    const authHeader = req.headers.get('x-webhook-secret');
 26→    const expectedSecret = Deno.env.get('N8N_WEBHOOK_SECRET');
 27→
 28→    if (!expectedSecret || authHeader !== expectedSecret) {
 29→      return new Response(
 30→        JSON.stringify({ success: false, error: { code: 'UNAUTHORIZED', message: 'Invalid webhook secret' } }),
 31→        { status: 401, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
 32→      );
 33→    }
 34→
 35→    const supabase = createClient(
 36→      Deno.env.get('SUPABASE_URL')!,
 37→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 38→    );
 39→
 40→    const now = new Date();
 41→    const threeDaysFromNow = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000);
 42→
 43→    // 1. Find trials expiring within 3 days (for reminders)
 44→    const { data: expiringTrials } = await supabase
 45→      .from('merchants')
 46→      .select('id, profile_id, business_name, trial_ends_at')
 47→      .eq('subscription_status', 'trial')
 48→      .lte('trial_ends_at', threeDaysFromNow.toISOString())
 49→      .gt('trial_ends_at', now.toISOString());
 50→
 51→    const reminders: string[] = [];
 52→
 53→    if (expiringTrials && expiringTrials.length > 0) {
 54→      for (const merchant of expiringTrials) {
 55→        const trialEnd = new Date(merchant.trial_ends_at);
 56→        const daysLeft = Math.max(
 57→          0,
 58→          Math.ceil((trialEnd.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
 59→        );
 60→
 61→        // Check if we already sent a reminder today
 62→        const todayStart = new Date(now);
 63→        todayStart.setHours(0, 0, 0, 0);
 64→
 65→        const { data: existingLog } = await supabase
 66→          .from('billing_events')
 67→          .select('id')
 68→          .eq('merchant_id', merchant.id)
 69→          .eq('event_type', 'trial_expiry_reminder')
 70→          .gte('created_at', todayStart.toISOString())
 71→          .limit(1);
 72→
 73→        if (existingLog && existingLog.length > 0) continue;
 74→
 75→        // Send push notification
 76→        const { data: playerIds } = await supabase
 77→          .from('onesignal_subscriptions')
 78→          .select('player_id')
 79→          .eq('profile_id', merchant.profile_id)
 80→          .eq('is_active', true);
 81→
 82→        if (playerIds && playerIds.length > 0) {
 83→          const appId = Deno.env.get('ONESIGNAL_APP_ID');
 84→          const apiKey = Deno.env.get('ONESIGNAL_REST_API_KEY');
 85→
 86→          if (appId && apiKey) {
 87→            try {
 88→              await fetch('https://onesignal.com/api/v1/notifications', {
 89→                method: 'POST',
 90→                headers: {
 91→                  'Content-Type': 'application/json',
 92→                  Authorization: `Basic ${apiKey}`,
 93→                },
 94→                body: JSON.stringify({
 95→                  app_id: appId,
 96→                  include_player_ids: playerIds.map((p: any) => p.player_id),
 97→                  headings: { fr: 'Essai gratuit bientot termine' },
 98→                  contents: {
 99→                    fr: `Il vous reste ${daysLeft} jour${daysLeft > 1 ? 's' : ''} d'essai. Choisissez un plan pour continuer a utiliser AstroLab.`,
100→                  },
101→                  url: `${Deno.env.get('APP_URL') || 'http://localhost:5173'}/merchant/billing`,
102→                }),
103→              });
104→            } catch {
105→              // Push failed, continue
106→            }
107→          }
108→        }
109→
110→        // Log the reminder
111→        await supabase.from('billing_events').insert({
112→          merchant_id: merchant.id,
113→          event_type: 'trial_expiry_reminder',
114→          plan: 'trial',
115→          metadata: { days_left: daysLeft },
116→        });
117→
118→        reminders.push(merchant.id);
119→      }
120→    }
121→
122→    // 2. Find expired trials (past trial_ends_at)
123→    const { data: expiredTrials } = await supabase
124→      .from('merchants')
125→      .select('id, business_name, profile_id')
126→      .eq('subscription_status', 'trial')
127→      .lt('trial_ends_at', now.toISOString());
128→
129→    const expired: string[] = [];
130→
131→    if (expiredTrials && expiredTrials.length > 0) {
132→      for (const merchant of expiredTrials) {
133→        // Downgrade to cancelled
134→        await supabase
135→          .from('merchants')
136→          .update({
137→            subscription_status: 'cancelled',
138→            subscription_plan: 'starter',
139→          })
140→          .eq('id', merchant.id);
141→
142→        // Log the expiry
143→        await supabase.from('billing_events').insert({
144→          merchant_id: merchant.id,
145→          event_type: 'trial_expired',
146→          plan: 'starter',
147→          previous_plan: 'trial',
148→        });
149→
150→        // Send push notification
151→        const { data: playerIds } = await supabase
152→          .from('onesignal_subscriptions')
153→          .select('player_id')
154→          .eq('profile_id', merchant.profile_id)
155→          .eq('is_active', true);
156→
157→        if (playerIds && playerIds.length > 0) {
158→          const appId = Deno.env.get('ONESIGNAL_APP_ID');
159→          const apiKey = Deno.env.get('ONESIGNAL_REST_API_KEY');
160→
161→          if (appId && apiKey) {
162→            try {
163→              await fetch('https://onesignal.com/api/v1/notifications', {
164→                method: 'POST',
165→                headers: {
166→                  'Content-Type': 'application/json',
167→                  Authorization: `Basic ${apiKey}`,
168→                },
169→                body: JSON.stringify({
170→                  app_id: appId,
171→                  include_player_ids: playerIds.map((p: any) => p.player_id),
172→                  headings: { fr: 'Essai gratuit termine' },
173→                  contents: {
174→                    fr: 'Votre essai AstroLab est termine. Choisissez un plan pour continuer a fideliser vos clients.',
175→                  },
176→                  url: `${Deno.env.get('APP_URL') || 'http://localhost:5173'}/merchant/billing`,
177→                }),
178→              });
179→            } catch {
180→              // Push failed, continue
181→            }
182→          }
183→        }
184→
185→        expired.push(merchant.id);
186→      }
187→    }
188→
189→    return new Response(
190→      JSON.stringify({
191→        success: true,
192→        data: {
193→          reminders_sent: reminders.length,
194→          trials_expired: expired.length,
195→          reminder_ids: reminders,
196→          expired_ids: expired,
197→        },
198→      }),
199→      {
200→        status: 200,
201→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
202→      }
203→    );
204→  } catch (err: any) {
205→    return new Response(
206→      JSON.stringify({
207→        success: false,
208→        error: { code: 'INTERNAL_ERROR', message: err.message },
209→      }),
210→      {
211→        status: 500,
212→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
213→      }
214→    );
215→  }
216→});
