  1→import { supabaseAdmin } from '../_shared/supabase-admin.ts';
  2→import { getAuthUser } from '../_shared/auth.ts';
  3→import {
  4→  successResponse,
  5→  errorResponse,
  6→  corsResponse,
  7→} from '../_shared/responses.ts';
  8→
  9→Deno.serve(async (req) => {
 10→  if (req.method === 'OPTIONS') {
 11→    return corsResponse();
 12→  }
 13→
 14→  try {
 15→    // 1. Authentification marchand
 16→    const user = await getAuthUser(req);
 17→    if (!user) {
 18→      return errorResponse('NOT_AUTHENTICATED', 'Le marchand doit etre connecte', 401);
 19→    }
 20→
 21→    // 2. Parser le body
 22→    const { token } = await req.json();
 23→    if (!token) {
 24→      return errorResponse('INVALID_TOKEN', 'Token QR manquant');
 25→    }
 26→
 27→    // 3. Valider le token QR
 28→    const { data: qrCode, error: qrError } = await supabaseAdmin
 29→      .from('qr_codes')
 30→      .select('*')
 31→      .eq('token', token)
 32→      .eq('is_active', true)
 33→      .single();
 34→
 35→    if (qrError || !qrCode) {
 36→      return errorResponse('INVALID_TOKEN', 'Token QR non trouve ou inactif');
 37→    }
 38→
 39→    if (qrCode.qr_type !== 'campaign') {
 40→      return errorResponse('NOT_CAMPAIGN_QR', 'Ce QR n\'est pas un QR campagne');
 41→    }
 42→
 43→    // 4. Verifier que le marchand connecte est le bon
 44→    const { data: merchant } = await supabaseAdmin
 45→      .from('merchants')
 46→      .select('id')
 47→      .eq('profile_id', user.id)
 48→      .single();
 49→
 50→    if (!merchant || merchant.id !== qrCode.merchant_id) {
 51→      return errorResponse('WRONG_MERCHANT', 'Ce QR n\'appartient pas a ce marchand');
 52→    }
 53→
 54→    // 5. Verifier expiration
 55→    if (qrCode.expires_at && new Date(qrCode.expires_at) < new Date()) {
 56→      return errorResponse('QR_EXPIRED', 'Ce QR code est expire');
 57→    }
 58→
 59→    // 6. Verifier max_uses
 60→    if (qrCode.uses_count >= qrCode.max_uses) {
 61→      return errorResponse('QR_MAX_USES', 'Nombre maximum d\'utilisations atteint');
 62→    }
 63→
 64→    // 7. Verifier unicite de redemption
 65→    if (!qrCode.campaign_id || !qrCode.customer_id) {
 66→      return errorResponse('INVALID_TOKEN', 'QR campagne incomplet (campaign_id ou customer_id manquant)');
 67→    }
 68→
 69→    const { data: existingRedemption } = await supabaseAdmin
 70→      .from('campaign_redemptions')
 71→      .select('id')
 72→      .eq('campaign_id', qrCode.campaign_id)
 73→      .eq('customer_id', qrCode.customer_id)
 74→      .maybeSingle();
 75→
 76→    if (existingRedemption) {
 77→      return errorResponse('ALREADY_REDEEMED', 'Ce client a deja utilise cette offre');
 78→    }
 79→
 80→    // 8. Recuperer les infos campagne
 81→    const { data: campaign, error: campaignError } = await supabaseAdmin
 82→      .from('campaigns')
 83→      .select('title, offer_description')
 84→      .eq('id', qrCode.campaign_id)
 85→      .single();
 86→
 87→    if (campaignError || !campaign) {
 88→      return errorResponse('CAMPAIGN_NOT_FOUND', 'Campagne introuvable');
 89→    }
 90→
 91→    // 9. Recuperer le nom du client
 92→    const { data: customer } = await supabaseAdmin
 93→      .from('customers')
 94→      .select('id, profile_id')
 95→      .eq('id', qrCode.customer_id)
 96→      .single();
 97→
 98→    let customerName = 'Client';
 99→    if (customer) {
100→      const { data: profile } = await supabaseAdmin
101→        .from('profiles')
102→        .select('full_name')
103→        .eq('id', customer.profile_id)
104→        .single();
105→      if (profile?.full_name) {
106→        customerName = profile.full_name;
107→      }
108→    }
109→
110→    // 10. Creer la redemption (le trigger validate_qr_redemption gerera les verifications supplementaires)
111→    const { error: redemptionError } = await supabaseAdmin
112→      .from('campaign_redemptions')
113→      .insert({
114→        campaign_id: qrCode.campaign_id,
115→        customer_id: qrCode.customer_id,
116→        qr_code_id: qrCode.id,
117→        merchant_id: qrCode.merchant_id,
118→      });
119→
120→    if (redemptionError) {
121→      // Le trigger peut rejeter l'insertion
122→      return errorResponse('REDEMPTION_FAILED', redemptionError.message);
123→    }
124→
125→    // 11. Reponse
126→    return successResponse({
127→      campaign_title: campaign.title,
128→      customer_name: customerName,
129→      offer_description: campaign.offer_description || 'Offre speciale',
130→      redeemed_at: new Date().toISOString(),
131→    });
132→  } catch (err) {
133→    return errorResponse('INTERNAL_ERROR', 'Erreur serveur inattendue', 500);
134→  }
135→});
