 11→export function ScanResult() {
 12→  const { token } = useParams<{ token: string }>();
 13→  const { isAuthenticated, loading: authLoading } = useAuth();
 14→  const { subscribeToMerchant } = usePush();
 15→  const navigate = useNavigate();
 16→
 17→  const [result, setResult] = useState<CustomerScanResponse | null>(null);
 18→  const [loading, setLoading] = useState(false);
 19→
 20→  useEffect(() => {
 21→    if (authLoading) return;
 22→
 23→    if (!isAuthenticated) {
 24→      navigate(`/login?redirect=/scan/${token}`, { replace: true });
 25→      return;
 26→    }
 27→
 28→    if (!token) return;
 29→
 30→    async function doScan() {
 31→      setLoading(true);
 32→      const res = await callEdgeFunction<CustomerScanResponse>(
 33→        'process-customer-scan',
 34→        { token }
 35→      );
 36→      setResult(res);
 37→
 38→      // Auto-subscribe to merchant notifications on first scan
 39→      if (res.success && res.data?.is_first_scan && res.data.merchant_id) {
 40→        subscribeToMerchant(res.data.merchant_id).catch(() => {});
 41→      }
 42→
 43→      setLoading(false);
 44→    }
 45→
 46→    doScan();
 47→  }, [token, isAuthenticated, authLoading, navigate, subscribeToMerchant]);
 48→
 49→  if (authLoading || loading) {
 50→    return (
 51→      <div className="flex min-h-screen items-center justify-center bg-[var(--color-bg)]">
 52→        <div className="text-center">
 53→          <Spinner size="lg" />
 54→          <p className="mt-4 text-[var(--color-text-muted)]">
 55→            Validation du scan...
 56→          </p>
 57→        </div>
 58→      </div>
 59→    );
 60→  }
 61→
 62→  if (!result) {
 63→    return null;
 64→  }
 65→
 66→  // Erreur
 67→  if (!result.success) {
 68→    const errorMessages: Record<string, string> = {
 69→      INVALID_TOKEN: 'Ce QR code est invalide ou inactif.',
 70→      NOT_COUNTER_QR: 'Ce QR code n\'est pas un QR comptoir.',
 71→      NOT_AUTHENTICATED: 'Vous devez etre connecte pour scanner.',
 72→      SCAN_TOO_RECENT: 'Scan trop recent ! Veuillez attendre 5 minutes.',
 73→      MERCHANT_NOT_FOUND: 'Commercant introuvable.',
 74→    };
 75→
 76→    const message =
 77→      errorMessages[result.error?.code ?? ''] ||
 78→      result.error?.message ||
 79→      'Une erreur est survenue.';
 80→
 81→    return (
 82→      <div className="flex min-h-screen items-center justify-center bg-[var(--color-bg)] px-4">
 83→        <Card className="max-w-md text-center">
 84→          <div className="mb-4 text-5xl">&#10060;</div>
 85→          <h2 className="mb-2 text-xl font-bold text-[var(--color-text)]">
 86→            Scan echoue
 87→          </h2>
 88→          <p className="mb-6 text-[var(--color-text-muted)]">{message}</p>
 89→          <Link to="/">
 90→            <Button variant="outline">Retour a l'accueil</Button>
 91→          </Link>
 92→        </Card>
 93→      </div>
 94→    );
 95→  }
 96→
 97→  // Succes
 98→  const d = result.data!;
 99→
100→  return (
101→    <div className="flex min-h-screen items-center justify-center bg-[var(--color-bg)] px-4">
102→      <Card className="max-w-md text-center">
103→        <div className="mb-4 text-5xl">&#10004;&#65039;</div>
104→        <h2 className="mb-2 text-xl font-bold text-[var(--color-text)]">
105→          Scan valide !
106→        </h2>
107→        <p className="mb-4 text-lg text-[var(--color-primary)]">
108→          {d.merchant_name}
109→        </p>
110→
111→        <div className="mb-6 space-y-2 rounded-lg bg-slate-50 p-4">
112→          {d.points_earned > 0 && (
113→            <p className="text-sm text-[var(--color-text)]">
114→              <span className="font-semibold">+{d.points_earned}</span> points
115→              gagnes (total : {d.total_points})
116→            </p>
117→          )}
118→          {d.stamps_earned > 0 && (
119→            <p className="text-sm text-[var(--color-text)]">
120→              <span className="font-semibold">+{d.stamps_earned}</span> tampon
121→              {d.stamps_earned > 1 ? 's' : ''} (
122→              {d.stamps_current_card}/{d.stamps_per_card})
123→            </p>
124→          )}
125→          {d.card_completed && (
126→            <p className="mt-2 font-bold text-green-600">
127→              &#127881; Carte completee ! Reclamez votre recompense !
128→            </p>
129→          )}
130→        </div>
131→
132→        <Link to="/customer/dashboard">
133→          <Button className="w-full">Voir mes cartes de fidelite</Button>
134→        </Link>
135→      </Card>
136→    </div>
137→  );
138→}
