 24→  useEffect(() => {
 25→    if (!token) return;
 26→
 27→    async function loadOffer() {
 28→      // Recuperer le QR code et la campagne liee
 29→      const { data: qrCode, error: qrError } = await supabase
 30→        .from('qr_codes')
 31→        .select('*, campaigns!qr_codes_campaign_id_fkey(title, offer_description)')
 32→        .eq('token', token)
 33→        .eq('qr_type', 'campaign')
