  1→/**
  2→ * n8n helper for Supabase Edge Functions (Deno).
  3→ * Used by triggers to notify n8n workflows.
  4→ * Fire-and-forget pattern — errors are logged but don't block callers.
  5→ */
  6→
  7→const N8N_BASE_URL = Deno.env.get('N8N_BASE_URL') || '';
  8→const N8N_WEBHOOK_SECRET = Deno.env.get('N8N_WEBHOOK_SECRET') || '';
  9→
 10→/**
 11→ * Sign a payload with HMAC-SHA256
 12→ */
 13→async function signPayload(payload: string): Promise<string> {
 14→  if (!N8N_WEBHOOK_SECRET) return '';
 15→  const encoder = new TextEncoder();
 16→  const key = await crypto.subtle.importKey(
 17→    'raw',
 18→    encoder.encode(N8N_WEBHOOK_SECRET),
 19→    { name: 'HMAC', hash: 'SHA-256' },
 20→    false,
 21→    ['sign']
 22→  );
 23→  const sig = await crypto.subtle.sign('HMAC', key, encoder.encode(payload));
 24→  return Array.from(new Uint8Array(sig))
 25→    .map((b) => b.toString(16).padStart(2, '0'))
 26→    .join('');
 27→}
 28→
 29→/**
 30→ * Trigger an n8n workflow via its webhook path.
 31→ * Fire-and-forget: errors are logged to console but don't throw.
 32→ */
 33→export async function triggerN8nWorkflow(
 34→  webhookPath: string,
 35→  data: unknown
 36→): Promise<void> {
 37→  if (!N8N_BASE_URL) {
 38→    console.warn('[n8n] N8N_BASE_URL not configured, skipping trigger');
 39→    return;
 40→  }
 41→
 42→  try {
 43→    const body = JSON.stringify(data);
 44→    const signature = await signPayload(body);
 45→
 46→    const url = `${N8N_BASE_URL}${webhookPath}`;
 47→    const res = await fetch(url, {
 48→      method: 'POST',
 49→      headers: {
 50→        'Content-Type': 'application/json',
 51→        'x-webhook-signature': signature,
 52→      },
 53→      body,
 54→    });
 55→
 56→    if (!res.ok) {
 57→      const text = await res.text();
 58→      console.error(`[n8n] Trigger failed: ${res.status} — ${text}`);
 59→    }
 60→  } catch (err) {
 61→    console.error('[n8n] Trigger error:', err);
 62→  }
 63→}
 64→
 65→/**
 66→ * Log a workflow execution to workflow_logs table via the webhook handler.
 67→ */
 68→export interface WorkflowLogInput {
 69→  workflow_name: string;
 70→  workflow_run_id?: string;
 71→  merchant_id?: string;
 72→  status: 'started' | 'success' | 'error' | 'retrying' | 'dead_letter';
 73→  input_data?: Record<string, unknown>;
 74→  output_data?: Record<string, unknown>;
 75→  error_message?: string;
 76→  retry_count?: number;
 77→  duration_ms?: number;
 78→}
 79→
 80→export async function logWorkflow(params: WorkflowLogInput): Promise<void> {
 81→  // Import supabaseAdmin inline to avoid circular deps
 82→  const { supabaseAdmin } = await import('./supabase-admin.ts');
 83→
 84→  try {
 85→    await supabaseAdmin.from('workflow_logs').insert({
 86→      workflow_name: params.workflow_name,
 87→      workflow_run_id: params.workflow_run_id || null,
 88→      merchant_id: params.merchant_id || null,
 89→      status: params.status,
 90→      input_data: params.input_data || null,
 91→      output_data: params.output_data || null,
 92→      error_message: params.error_message || null,
 93→      retry_count: params.retry_count || 0,
 94→      duration_ms: params.duration_ms || null,
 95→    });
 96→  } catch (err) {
 97→    console.error('[n8n] Log workflow error:', err);
 98→  }
 99→}
