 17→    [Deno.env.get('STRIPE_PRICE_STARTER') || '']: 'starter',
 18→    [Deno.env.get('STRIPE_PRICE_PRO') || '']: 'pro',
 19→    [Deno.env.get('STRIPE_PRICE_BUSINESS') || '']: 'business',
 20→  };
 21→  return map[priceId] || 'starter';
