 26→// -------------------------------------------------------
 27→export function mapStripeStatus(stripeStatus: string): string {
 28→  const map: Record<string, string> = {
 29→    active: 'active',
 30→    trialing: 'trial',
 31→    past_due: 'past_due',
 32→    canceled: 'cancelled',
 33→    unpaid: 'past_due',
 34→    incomplete: 'past_due',
 35→    incomplete_expired: 'cancelled',
 36→    paused: 'cancelled',
 37→  };
