 53→// -------------------------------------------------------
 54→// Notify merchant (push notification)
 55→// -------------------------------------------------------
 56→export async function notifyMerchant(
 57→  merchantId: string,
 58→  notification: { title: string; message: string }
 59→) {
 60→  // Get profile_id from merchant
 61→  const { data: merchant } = await supabaseAdmin
 62→    .from('merchants')
 63→    .select('profile_id')
 64→    .eq('id', merchantId)
 65→    .single();
 66→
 67→  if (!merchant) return;
 68→
 69→  // Get OneSignal player_id
 70→  const { data: sub } = await supabaseAdmin
 71→    .from('onesignal_subscriptions')
 72→    .select('player_id')
 73→    .eq('profile_id', merchant.profile_id)
 74→    .eq('is_active', true)
 75→    .limit(1)
 76→    .maybeSingle();
 77→
 78→  if (!sub?.player_id) return;
 79→
 80→  const ONESIGNAL_APP_ID = Deno.env.get('ONESIGNAL_APP_ID');
 81→  const ONESIGNAL_REST_API_KEY = Deno.env.get('ONESIGNAL_REST_API_KEY');
 82→
 83→  if (!ONESIGNAL_APP_ID || !ONESIGNAL_REST_API_KEY) return;
 84→
 85→  try {
 86→    await fetch('https://onesignal.com/api/v1/notifications', {
 87→      method: 'POST',
 88→      headers: {
 89→        'Content-Type': 'application/json',
 90→        Authorization: `Basic ${ONESIGNAL_REST_API_KEY}`,
 91→      },
 92→      body: JSON.stringify({
 93→        app_id: ONESIGNAL_APP_ID,
 94→        headings: { en: notification.title },
 95→        contents: { en: notification.message },
 96→        include_player_ids: [sub.player_id],
 97→        url: '/merchant/billing',
 98→      }),
 99→    });
100→  } catch (err) {
101→    console.error('Push notification failed:', err);
102→  }
103→}
